onClick:
{{
  (() => {
    const ids = (Table1.selectedRows || [])
      .map(r => r.id)
      .filter(Boolean);

    if (!ids.length) {
      showAlert("Sélectionne au moins une ligne.", "warning");
      return;
    }

    const action = RadioGroupForcage.selectedOptionValue; // "COMMANDE" ou "RECU"
    if (!action) {
      showAlert("Choisis 'Commandé' ou 'Reçu'.", "warning");
      return;
    }

    return QryForceReceptionAchats.run({ ids, action })
      .then(() => {
        showAlert(`Lignes validées : ${ids.length}`, "success");
        return QryAchatsNomenclature.run();
      })
      .catch(e => showAlert(e?.message || "Erreur", "error"));
  })()
}}
